import React, { useState } from 'react';

const App = () => {
  const [priceRange, setPriceRange] = useState({ min: 0, max: 100 });
  const [brand, setBrand] = useState([]);
  const [category, setCategory] = useState([]);

  const products = [
    { variant: ' Variant 1', brand: 'Brand A', category: 'Category 1', price: 50 },
    { variant: ' Variant 2', brand: 'Brand A', category: 'Category 1', price: 75 },
    { variant: ' Variant 3', brand: 'Brand B', category: 'Category 2', price: 25 },
    { variant: ' Variant 4', brand: 'Brand B', category: 'Category 2', price: 50 },
    { variant: ' Variant 5', brand: 'Brand C', category: 'Category 3', price: 100 }
  ];

  const handlePriceRangeChange = (e) => {
    const { min, max } = e.target.value.split(',');
    setPriceRange({ min: parseInt(min), max: parseInt(max) });
  };

  const handleBrandChange = (e) => {
    setBrand(e.target.value);
  };

  const handleCategoryChange = (e) => {
    setCategory(e.target.value);
  };

  const filteredProducts = products.filter((product) => {
    return product.price >= priceRange.min && product.price <= priceRange.max && product.brand === brand && product.category === category;
  });

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#B7D7CD] p-4 rounded">
        <h2 className="text-[#C06C88] font-bold text-2xl mb-4">Pricing Matrix</h2>
        <div className="flex flex-wrap">
          <div className="w-1/2 md:w-1/3 lg:w-1/4 p-2 mb-4">
            <input
              type="range"
              className="w-full h-2 bg-[#B7D7CD] appearance-none rounded"
              min="0"
              max="100"
              value={`${priceRange.min},${priceRange.max}`}
              onChange={handlePriceRangeChange}
              step="1"
            />
            <label className="block text-[#411C56] text-sm">Price Range: {priceRange.min} - {priceRange.max}</label>
          </div>
          <div className="w-1/2 md:w-1/3 lg:w-1/4 p-2 mb-4">
            <select
              className="w-full border border-[#B7D7CD] rounded p-2"
              value={brand}
              onChange={handleBrandChange}
            >
              <option value="">Brand</option>
              <option value="Brand A">Brand A</option>
              <option value="Brand B">Brand B</option>
              <option value="Brand C">Brand C</option>
            </select>
          </div>
          <div className="w-1/2 md:w-1/3 lg:w-1/4 p-2 mb-4">
            <select
              className="w-full border border-[#B7D7CD] rounded p-2"
              value={category}
              onChange={handleCategoryChange}
            >
              <option value="">Category</option>
              <option value="Category 1">Category 1</option>
              <option value="Category 2">Category 2</option>
              <option value="Category 3">Category 3</option>
            </select>
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-[#B7D7CD]">
            <thead className="bg-[#C06C88]">
              <tr>
                <th className="px-6 py-3 text-left text-[#411C56]">Variant</th>
                <th className="px-6 py-3 text-left text-[#411C56]">Brand</th>
                <th className="px-6 py-3 text-left text-[#411C56]">Category</th>
                <th className="px-6 py-3 text-left text-[#411C56]">Price</th>
              </tr>
            </thead>
            <tbody>
              {filteredProducts.map((product, index) => (
                <tr key={index} className="bg-white hover:bg-[#B7D7CD]">
                  <td className="px-6 py-4 text-left text-[#411C56]">{product.variant}</td>
                  <td className="px-6 py-4 text-left text-[#411C56]">{product.brand}</td>
                  <td className="px-6 py-4 text-left text-[#411C56]">{product.category}</td>
                  <td className="px-6 py-4 text-left text-[#411C56]">${product.price}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default App;
